#include <cuda_runtime.h>
#include <stdio.h>
#include <stdlib.h>

#ifdef RD_WG_SIZE_0_0
    #define BLOCK_SIZE RD_WG_SIZE_0_0
#elif defined(RD_WG_SIZE_0)
    #define BLOCK_SIZE RD_WG_SIZE_0
#elif defined(RD_WG_SIZE)
    #define BLOCK_SIZE RD_WG_SIZE
#else
    #define BLOCK_SIZE 16
#endif

static inline void cuda_check(cudaError_t err, const char *file, int line)
{
    if (err != cudaSuccess)
    {
        fprintf(stderr, "CUDA error at %s:%d: %s\n", file, line, cudaGetErrorString(err));
        exit(EXIT_FAILURE);
    }
}

#define CUDA_CHECK(call) cuda_check((call), __FILE__, __LINE__)

__device__ __forceinline__ int maximum_device(int a, int b, int c)
{
    int k;
    if (a <= b)
        k = b;
    else
        k = a;

    if (k <= c)
        return c;
    else
        return k;
}

__global__ void nw_top_left_kernel(int *input_itemsets, const int *referrence,
                                   int max_cols, int penalty, int blk)
{
    int b_index_x = blockIdx.x;
    if (b_index_x >= blk)
        return;

    int b_index_y = blk - 1 - b_index_x;

    int input_itemsets_l[(BLOCK_SIZE + 1) * (BLOCK_SIZE + 1)];
    int reference_l[BLOCK_SIZE * BLOCK_SIZE];

    for (int i = 0; i < BLOCK_SIZE; ++i)
    {
        for (int j = 0; j < BLOCK_SIZE; ++j)
        {
            reference_l[i * BLOCK_SIZE + j] =
                referrence[max_cols * (b_index_y * BLOCK_SIZE + i + 1) +
                           b_index_x * BLOCK_SIZE + j + 1];
        }
    }

    for (int i = 0; i < BLOCK_SIZE + 1; ++i)
    {
        for (int j = 0; j < BLOCK_SIZE + 1; ++j)
        {
            input_itemsets_l[i * (BLOCK_SIZE + 1) + j] =
                input_itemsets[max_cols * (b_index_y * BLOCK_SIZE + i) +
                               b_index_x * BLOCK_SIZE + j];
        }
    }

    for (int i = 1; i < BLOCK_SIZE + 1; ++i)
    {
        for (int j = 1; j < BLOCK_SIZE + 1; ++j)
        {
            input_itemsets_l[i * (BLOCK_SIZE + 1) + j] =
                maximum_device(
                    input_itemsets_l[(i - 1) * (BLOCK_SIZE + 1) + j - 1] +
                        reference_l[(i - 1) * BLOCK_SIZE + j - 1],
                    input_itemsets_l[i * (BLOCK_SIZE + 1) + j - 1] - penalty,
                    input_itemsets_l[(i - 1) * (BLOCK_SIZE + 1) + j] - penalty);
        }
    }

    for (int i = 0; i < BLOCK_SIZE; ++i)
    {
        for (int j = 0; j < BLOCK_SIZE; ++j)
        {
            input_itemsets[max_cols * (b_index_y * BLOCK_SIZE + i + 1) +
                           b_index_x * BLOCK_SIZE + j + 1] =
                input_itemsets_l[(i + 1) * (BLOCK_SIZE + 1) + j + 1];
        }
    }
}

__global__ void nw_bottom_right_kernel(int *input_itemsets, const int *referrence,
                                       int max_cols, int penalty, int blk, int total_blocks)
{
    int local_block = blockIdx.x;
    int b_index_x = local_block + blk - 1;
    if (b_index_x >= total_blocks)
        return;

    int b_index_y = total_blocks + blk - 2 - b_index_x;

    int input_itemsets_l[(BLOCK_SIZE + 1) * (BLOCK_SIZE + 1)];
    int reference_l[BLOCK_SIZE * BLOCK_SIZE];

    for (int i = 0; i < BLOCK_SIZE; ++i)
    {
        for (int j = 0; j < BLOCK_SIZE; ++j)
        {
            reference_l[i * BLOCK_SIZE + j] =
                referrence[max_cols * (b_index_y * BLOCK_SIZE + i + 1) +
                           b_index_x * BLOCK_SIZE + j + 1];
        }
    }

    for (int i = 0; i < BLOCK_SIZE + 1; ++i)
    {
        for (int j = 0; j < BLOCK_SIZE + 1; ++j)
        {
            input_itemsets_l[i * (BLOCK_SIZE + 1) + j] =
                input_itemsets[max_cols * (b_index_y * BLOCK_SIZE + i) +
                               b_index_x * BLOCK_SIZE + j];
        }
    }

    for (int i = 1; i < BLOCK_SIZE + 1; ++i)
    {
        for (int j = 1; j < BLOCK_SIZE + 1; ++j)
        {
            input_itemsets_l[i * (BLOCK_SIZE + 1) + j] =
                maximum_device(
                    input_itemsets_l[(i - 1) * (BLOCK_SIZE + 1) + j - 1] +
                        reference_l[(i - 1) * BLOCK_SIZE + j - 1],
                    input_itemsets_l[i * (BLOCK_SIZE + 1) + j - 1] - penalty,
                    input_itemsets_l[(i - 1) * (BLOCK_SIZE + 1) + j] - penalty);
        }
    }

    for (int i = 0; i < BLOCK_SIZE; ++i)
    {
        for (int j = 0; j < BLOCK_SIZE; ++j)
        {
            input_itemsets[max_cols * (b_index_y * BLOCK_SIZE + i + 1) +
                           b_index_x * BLOCK_SIZE + j + 1] =
                input_itemsets_l[(i + 1) * (BLOCK_SIZE + 1) + j + 1];
        }
    }
}

void nw_optimized(int *input_itemsets, int *output_itemsets, int *referrence,
                  int max_rows, int max_cols, int penalty)
{
    (void)output_itemsets;

    int *d_input_itemsets = NULL;
    int *d_referrence = NULL;
    size_t transfer_size = (size_t)max_rows * (size_t)max_cols * sizeof(int);
    int total_blocks = (max_cols - 1) / BLOCK_SIZE;

    CUDA_CHECK(cudaMalloc((void **)&d_input_itemsets, transfer_size));
    CUDA_CHECK(cudaMalloc((void **)&d_referrence, transfer_size));

    CUDA_CHECK(cudaMemcpy(d_input_itemsets, input_itemsets, transfer_size, cudaMemcpyHostToDevice));
    CUDA_CHECK(cudaMemcpy(d_referrence, referrence, transfer_size, cudaMemcpyHostToDevice));

    for (int blk = 1; blk <= total_blocks; blk++)
    {
        nw_top_left_kernel<<<blk, 1>>>(d_input_itemsets, d_referrence, max_cols, penalty, blk);
        CUDA_CHECK(cudaGetLastError());
    }

    CUDA_CHECK(cudaDeviceSynchronize());

    printf("Processing bottom-right matrix\n");

    for (int blk = 2; blk <= total_blocks; blk++)
    {
        int grid_x = total_blocks - blk + 1;
        nw_bottom_right_kernel<<<grid_x, 1>>>(d_input_itemsets, d_referrence, max_cols, penalty, blk, total_blocks);
        CUDA_CHECK(cudaGetLastError());
    }

    CUDA_CHECK(cudaDeviceSynchronize());

    CUDA_CHECK(cudaMemcpy(input_itemsets, d_input_itemsets, transfer_size, cudaMemcpyDeviceToHost));

    CUDA_CHECK(cudaFree(d_input_itemsets));
    CUDA_CHECK(cudaFree(d_referrence));
}
